package main

import (
    "fmt"
    "time"
)

func main() {
    // ---- Creating channels ----
    ch := make(chan string)

    // ---- Sending and receiving ----
    go func() {
        ch <- "Hello from goroutine"
    }()

    msg := <-ch
    fmt.Println(msg)

    // ---- Multiple sends and receives ----
    go func() {
        for i := 1; i <= 3; i++ {
            ch <- fmt.Sprintf("Message %d", i)
            time.Sleep(50 * time.Millisecond)
        }
        close(ch)
    }()

    for msg := range ch {
        fmt.Println(msg)
    }

    // ---- Buffered channels ----
    buffered := make(chan int, 3)

    buffered <- 1
    buffered <- 2
    buffered <- 3
    // buffered <- 4  // Would block (buffer full)

    fmt.Println(<-buffered)
    fmt.Println(<-buffered)
    fmt.Println(<-buffered)

    // ---- Channel with goroutines ----
    result := make(chan int)

    go func() {
        result <- 42
    }()

    value := <-result
    fmt.Println("Result:", value)
}

